      setEngvoCallPhase('assistantPending')
    } else {
      setEngvoCallPhase('listening')
    }
    setMessages((prev) => prev.filter((m) => !m.engvoServiceLine))
  } else if (!engvoGreetingTriggeredRef.current) {
    const greetingSent = sendEngvoRealtimeEvent({
